window.chineseSwitcher={originalHTML:null,plainTextVersion:null,converter:null,init:function(){window.OpenCC?(this.converter=OpenCC.Converter({from:"tw",to:"cn"}),this.initSwitcher()):setTimeout(()=>this.init(),100)},convertTextNodes:function(e,t){const s=document.createTreeWalker(e,NodeFilter.SHOW_TEXT,null,!1),n=[];for(;s.nextNode();)n.push(s.currentNode);for(let e=n.length-1;e>=0;e--){const s=n[e];s.textContent.trim()&&(s.textContent=t(s.textContent))}},initSwitcher:function(){const n=document.querySelector("article");if(!n)return;this.originalHTML=n.innerHTML;const t=document.querySelector('[data-lang="zh-tw"]'),e=document.querySelector('[data-lang="zh-cn"]');if(!t||!e)return;e.addEventListener("click",()=>{if(e.classList.contains("active"))return;e.classList.add("active"),t.classList.remove("active"),this.convertTextNodes(n,this.converter),localStorage.setItem("preferredChinese","cn")}),t.addEventListener("click",()=>{if(t.classList.contains("active"))return;t.classList.add("active"),e.classList.remove("active"),this.originalHTML&&(n.innerHTML=this.originalHTML),localStorage.setItem("preferredChinese","tw"),window.bookmark&&window.bookmark.loadHighlights()});const s=localStorage.getItem("preferredChinese");s==="cn"&&e.click(),console.log("繁簡切換初始化完成")}}